@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">@ChildContent</div>

@code {
    /// <summary>Flex-direction keyword appended to the <c>flex-</c> Tailwind prefix (e.g. <c>"row"</c>, <c>"col"</c>, <c>"row-reverse"</c>). Defaults to <c>"row"</c>.</summary>
    [Parameter] public string? Direction { get; set; } = "row";

    /// <summary>Tailwind spacing scale suffix appended to <c>gap-</c> (e.g. <c>"2"</c>, <c>"4"</c>) to space out the children. Omitted when null/empty.</summary>
    [Parameter] public string? Gap { get; set; }

    /// <summary>Cross-axis alignment keyword appended to <c>items-</c> (e.g. <c>"center"</c>, <c>"start"</c>, <c>"stretch"</c>). Omitted when null/empty.</summary>
    [Parameter] public string? Align { get; set; }

    /// <summary>Main-axis distribution keyword appended to <c>justify-</c> (e.g. <c>"between"</c>, <c>"center"</c>, <c>"end"</c>). Omitted when null/empty.</summary>
    [Parameter] public string? Justify { get; set; }

    /// <summary>When <c>true</c>, adds <c>flex-wrap</c> so children wrap onto multiple lines instead of overflowing.</summary>
    [Parameter] public bool Wrap { get; set; }

    /// <summary>When <c>true</c>, renders as <c>inline-flex</c> instead of <c>flex</c>, so the container sits inline with surrounding content.</summary>
    [Parameter] public bool Inline { get; set; }

    /// <summary>The flex items rendered inside the container.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the container.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass
    {
        get
        {
            var display = Inline ? "inline-flex" : "flex";
            var direction = !string.IsNullOrEmpty(Direction) ? $"flex-{Direction}" : "";
            var gap = !string.IsNullOrEmpty(Gap) ? $"gap-{Gap}" : "";
            var align = !string.IsNullOrEmpty(Align) ? $"items-{Align}" : "";
            var justify = !string.IsNullOrEmpty(Justify) ? $"justify-{Justify}" : "";
            var wrap = Wrap ? "flex-wrap" : "";
            return Cx.Merge(display, direction, gap, align, justify, wrap, Class);
        }
    }
}
